#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding encounter-satisfaction (11 tables)..."

cargo loco generate scaffold patient \
    first_name:text! \
    last_name:text! \
    date_of_birth:date \
    sex:text! \
    --htmx

cargo loco generate scaffold encounter_satisfaction \
    patient:references \
    status:text! \
    --htmx

cargo loco generate scaffold visit_information \
    encounter_satisfaction:references \
    visit_date:date \
    department:text! \
    provider_name:text! \
    visit_type:text! \
    reason_for_visit:text! \
    first_visit:text! \
    --htmx

cargo loco generate scaffold access_scheduling \
    encounter_satisfaction:references \
    ease_of_scheduling:int \
    wait_for_appointment:int \
    wait_in_waiting_room:int \
    --htmx

cargo loco generate scaffold communication \
    encounter_satisfaction:references \
    listening:int \
    explaining_condition:int \
    answering_questions:int \
    time_spent:int \
    --htmx

cargo loco generate scaffold staff_professionalism \
    encounter_satisfaction:references \
    reception_courtesy:int \
    nursing_courtesy:int \
    respect_shown:int \
    --htmx

cargo loco generate scaffold care_quality \
    encounter_satisfaction:references \
    involvement_in_decisions:int \
    treatment_plan_explanation:int \
    confidence_in_care:int \
    --htmx

cargo loco generate scaffold environment \
    encounter_satisfaction:references \
    cleanliness:int \
    waiting_area_comfort:int \
    privacy:int \
    --htmx

cargo loco generate scaffold overall_satisfaction \
    encounter_satisfaction:references \
    overall_rating:int \
    likely_to_recommend:int \
    likely_to_return:int \
    comments:text! \
    --htmx

cargo loco generate scaffold satisfaction_result \
    encounter_satisfaction:references \
    composite_score:double! \
    category:text! \
    answered_count:int! \
    domain_scores:jsonb! \
    scored_at:ts! \
    --htmx

cargo loco generate scaffold flagged_issue \
    satisfaction_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
